import java.util.*;

public class StringValidator {
    public boolean isValidEmail(String email) {
        if (email == null || email.isBlank()) return false;
        return email.contains("@") && email.contains(".") && !email.startsWith("@") && !email.endsWith(".");
    }

    public boolean isValidPhone(String phone) {
        if (phone == null) return false;
        return phone.matches("\\d{10}");
    }

    public String capitalize(String s) {
        if (s == null || s.isEmpty()) return s;
        return Character.toUpperCase(s.charAt(0)) + s.substring(1).toLowerCase();
    }
}

public class ParameterizedTestRunner {
    private int passed = 0, failed = 0;

    public <T> void testWithParams(String testName, java.util.function.Function<T, Boolean> testFn,
                                    List<Object[]> cases) {
        System.out.println("Test: " + testName);
        for (Object[] testCase : cases) {
            @SuppressWarnings("unchecked")
            T input = (T) testCase[0];
            boolean expected = (Boolean) testCase[1];
            boolean actual = testFn.apply(input);
            String status = actual == expected ? "PASS" : "FAIL";
            System.out.printf("  %s: input=%-30s expected=%s actual=%s%n",
                status, "'" + input + "'", expected, actual);
            if (actual == expected) passed++; else failed++;
        }
    }

    public void printSummary() {
        System.out.println("\nResults: " + passed + " passed, " + failed + " failed");
    }
}

public class Main {
    public static void main(String[] args) {
        StringValidator validator = new StringValidator();
        ParameterizedTestRunner runner = new ParameterizedTestRunner();

        runner.testWithParams("isValidEmail",
            (String email) -> validator.isValidEmail(email),
            Arrays.asList(
                new Object[]{"user@example.com", true},
                new Object[]{"invalid-email", false},
                new Object[]{"@example.com", false},
                new Object[]{"", false},
                new Object[]{"a@b.org", true}
            ));

        runner.testWithParams("isValidPhone",
            (String phone) -> validator.isValidPhone(phone),
            Arrays.asList(
                new Object[]{"1234567890", true},
                new Object[]{"123", false},
                new Object[]{"12345678901", false},
                new Object[]{"abcdefghij", false}
            ));

        runner.printSummary();
    }
}

import java.util.*;

public class Order {
    public enum Status { PENDING, CONFIRMED, SHIPPED, DELIVERED, CANCELLED }

    private int id;
    private List<String> items = new ArrayList<>();
    private double total = 0;
    private Status status = Status.PENDING;

    public Order(int id) { this.id = id; }

    public void addItem(String item, double price) {
        items.add(item);
        total += price;
    }

    public boolean confirm() {
        if (status == Status.PENDING && !items.isEmpty()) {
            status = Status.CONFIRMED;
            return true;
        }
        return false;
    }

    public boolean ship() {
        if (status == Status.CONFIRMED) { status = Status.SHIPPED; return true; }
        return false;
    }

    public boolean cancel() {
        if (status == Status.PENDING || status == Status.CONFIRMED) {
            status = Status.CANCELLED; return true;
        }
        return false;
    }

    public int getId() { return id; }
    public List<String> getItems() { return items; }
    public double getTotal() { return total; }
    public Status getStatus() { return status; }
}

